const resolvers = {
    getAllProducts: async () => {
        try {
            const products = await Widgets.find();
            return products;
        } catch (error) {
            throw new Error(error);
        }
    },
    getProduct: async ({ id }) => {
      try{
            const product = await Widgets.findById(id);
            return product;
      }
      catch(error){
        throw new Error(error);
      }
    },
    createProduct: async ({ input }) => {
        // try {
        //     const product = await Widgets.create(input);
        //     return product;
        // } 
